import{_ as a,o as i,c as l,a2 as t}from"./chunks/framework.LN3EJxkW.js";const p=JSON.parse('{"title":"AI 工程 Roadmap：从零基础到生产级 AI 系统","description":"","frontmatter":{},"headers":[],"relativePath":"04-ai/roadmap.md","filePath":"04-ai/roadmap.md","lastUpdated":1784212366000}'),r={name:"04-ai/roadmap.md"};function n(o,e,d,s,h,u){return i(),l("div",null,[...e[0]||(e[0]=[t('<h1 id="ai-工程-roadmap-从零基础到生产级-ai-系统" tabindex="-1">AI 工程 Roadmap：从零基础到生产级 AI 系统 <a class="header-anchor" href="#ai-工程-roadmap-从零基础到生产级-ai-系统" aria-label="Permalink to &quot;AI 工程 Roadmap：从零基础到生产级 AI 系统&quot;">​</a></h1><p>AI 工具、模型与框架会快速变化，这条路线以相对稳定的原理和工程闭环为主干：任务定义、模型接口、上下文、检索、工具、工作流、评估、可靠性与安全。具体厂商和框架作为可替换实现持续更新。</p><h2 id="能力阶梯" tabindex="-1">能力阶梯 <a class="header-anchor" href="#能力阶梯" aria-label="Permalink to &quot;能力阶梯&quot;">​</a></h2><table tabindex="0"><thead><tr><th>阶段</th><th>能力目标</th><th>代表产出</th></tr></thead><tbody><tr><td>入门</td><td>能调用模型并理解输入、输出、Token 和限制</td><td>命令行 AI 小程序</td></tr><tr><td>初级</td><td>能构建稳定的结构化、流式 AI 功能</td><td>AI Chat 与结构化抽取</td></tr><tr><td>中级</td><td>能构建 RAG、Tool 和可评估 Workflow</td><td>文档助手与工具助手</td></tr><tr><td>高级</td><td>能构建可恢复、可观测、安全的 Agent</td><td>长任务 Agent Workflow</td></tr><tr><td>专项</td><td>能治理多模型、成本、质量和生产风险</td><td>AI 平台或企业工作台</td></tr></tbody></table><hr><h2 id="阶段零-编程、数据与-api-入门" tabindex="-1">阶段零：编程、数据与 API 入门 <a class="header-anchor" href="#阶段零-编程、数据与-api-入门" aria-label="Permalink to &quot;阶段零：编程、数据与 API 入门&quot;">​</a></h2><h3 id="必要编程基础" tabindex="-1">必要编程基础 <a class="header-anchor" href="#必要编程基础" aria-label="Permalink to &quot;必要编程基础&quot;">​</a></h3><ul><li>[ ] 选择 JavaScript/TypeScript 或 Python 作为第一门 AI 应用语言。</li><li>[ ] 变量、函数、对象/字典、数组/列表、模块、异常和异步。</li><li>[ ] 命令行、Git、包管理、虚拟环境和环境变量。</li><li>[ ] HTTP、JSON、REST API、状态码、认证和流式响应。</li><li>[ ] 文件读写、文本编码、CSV/JSONL 和基础数据清洗。</li><li>[ ] Secret 不进入代码和 Git；理解最小权限和费用上限。</li></ul><h3 id="第一次模型实验" tabindex="-1">第一次模型实验 <a class="header-anchor" href="#第一次模型实验" aria-label="Permalink to &quot;第一次模型实验&quot;">​</a></h3><ul><li>[ ] 使用 SDK 和原始 HTTP 各完成一次模型调用。</li><li>[ ] 记录模型标识、日期、输入、输出、Token、延迟和费用。</li><li>[ ] 实现 Streaming、取消、超时和错误展示。</li><li>[ ] 使用 Schema 获取结构化结果并进行运行时校验。</li><li>[ ] 为同一任务准备五条固定样例，比较两种提示或模型。</li></ul><p>验收：能独立完成一个命令行或网页 AI 小程序；错误、密钥、超时和输出校验都有明确处理。</p><hr><h2 id="阶段一-基础认知" tabindex="-1">阶段一：基础认知 <a class="header-anchor" href="#阶段一-基础认知" aria-label="Permalink to &quot;阶段一：基础认知&quot;">​</a></h2><ul><li>[ ] 训练、推理、参数、损失、泛化、过拟合。</li><li>[ ] 训练集、验证集、测试集和 Benchmark。</li><li>[ ] Tokenization、Context Window、输入输出成本。</li><li>[ ] Embedding、向量、点积、余弦相似度。</li><li>[ ] Transformer、Attention、Q/K/V、位置、自回归生成。</li><li>[ ] Pretraining、SFT、偏好优化、Prompt、RAG、Fine-tuning 的区别。</li></ul><p>必做：Token 实验室、内存语义搜索、模型参数对比实验。</p><p>验收：能解释 LLM 为什么能生成、为什么会幻觉，以及 Prompt、RAG、Tool、Fine-tuning 分别解决什么问题。</p><hr><h2 id="阶段二-模型-api-与-prompt" tabindex="-1">阶段二：模型 API 与 Prompt <a class="header-anchor" href="#阶段二-模型-api-与-prompt" aria-label="Permalink to &quot;阶段二：模型 API 与 Prompt&quot;">​</a></h2><h3 id="模型调用" tabindex="-1">模型调用 <a class="header-anchor" href="#模型调用" aria-label="Permalink to &quot;模型调用&quot;">​</a></h3><ul><li>[ ] System、User、Assistant。</li><li>[ ] 多轮、Streaming、Structured Output、Tool Calling、多模态。</li><li>[ ] 请求取消、超时、有限重试、限流和 Usage。</li><li>[ ] 统一模型 Client，不让业务直接依赖厂商结构。</li></ul><h3 id="prompt" tabindex="-1">Prompt <a class="header-anchor" href="#prompt" aria-label="Permalink to &quot;Prompt&quot;">​</a></h3><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Role + Task + Context + Constraints + Examples + Output Format + Failure Behavior</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><ul><li>[ ] 为同一任务编写三个版本。</li><li>[ ] 建立真实测试样例。</li><li>[ ] 使用 JSON Schema 和运行时校验。</li><li>[ ] Prompt 版本化。</li><li>[ ] 记录模型、参数、Token、延迟和成本。</li><li>[ ] 区分格式错误与内容错误。</li></ul><p>验收：不凭感觉判断 Prompt；能判断问题应由 Prompt、代码、RAG、Tool 或 Workflow 解决。</p><hr><h2 id="阶段三-context-engineering" tabindex="-1">阶段三：Context Engineering <a class="header-anchor" href="#阶段三-context-engineering" aria-label="Permalink to &quot;阶段三：Context Engineering&quot;">​</a></h2><p>上下文可能来自系统规则、当前输入、历史、文件、知识库、用户资料、项目状态、工具结果、搜索和记忆。</p><ul><li>[ ] 区分指令与数据。</li><li>[ ] 区分可信和不可信内容。</li><li>[ ] 建立 Token Budget。</li><li>[ ] 对长对话摘要，同时保留关键事实。</li><li>[ ] 去重、过滤过期和冲突信息。</li><li>[ ] 按用户和租户权限获取上下文。</li><li>[ ] 记录最终发给模型的内容。</li><li>[ ] 建立上下文调试页面。</li><li>[ ] 记忆可查看、修改、删除和过期。</li><li>[ ] 区分会话记忆、工作记忆、用户记忆、项目记忆和数据库事实。</li></ul><p>验收：能解释一次请求为什么包含这些上下文，以及为什么排除其他内容。</p><hr><h2 id="阶段四-ai-应用与-ai-ux" tabindex="-1">阶段四：AI 应用与 AI UX <a class="header-anchor" href="#阶段四-ai-应用与-ai-ux" aria-label="Permalink to &quot;阶段四：AI 应用与 AI UX&quot;">​</a></h2><p>状态：Idle、Preparing、Queued、Streaming、Tool Calling、Waiting Approval、Completed、Failed、Cancelled、Partial Success、Needs Input。</p><ul><li>[ ] 状态机。</li><li>[ ] Streaming、Stop、Retry、Continue。</li><li>[ ] 断线、重复事件、半截 JSON、部分结果保存。</li><li>[ ] 流式 Markdown 和未闭合代码块。</li><li>[ ] Artifact、Diff、History、Restore。</li><li>[ ] Citation、证据和无答案状态。</li><li>[ ] 不确定性、人工确认和人工接管。</li><li>[ ] 页面刷新后的长任务恢复。</li></ul><p>验收：用户始终知道系统在做什么，可以停止、修改、重试、确认和恢复。</p><hr><h2 id="阶段五-rag" tabindex="-1">阶段五：RAG <a class="header-anchor" href="#阶段五-rag" aria-label="Permalink to &quot;阶段五：RAG&quot;">​</a></h2><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>文档 → 解析 → 清洗 → Chunk → Embedding → 索引 → 查询处理 → 检索 → Rerank → Context → 生成 → 引用 → 评估</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="文档解析" tabindex="-1">文档解析 <a class="header-anchor" href="#文档解析" aria-label="Permalink to &quot;文档解析&quot;">​</a></h3><ul><li>[ ] PDF、Word、Markdown、HTML、表格、扫描件。</li><li>[ ] 保留标题、页码、来源和原文定位。</li><li>[ ] 去除重复页眉页脚。</li><li>[ ] 分别记录不同文件的解析质量。</li></ul><h3 id="chunk" tabindex="-1">Chunk <a class="header-anchor" href="#chunk" aria-label="Permalink to &quot;Chunk&quot;">​</a></h3><ul><li>[ ] 固定长度、段落、标题、语义、滑动窗口、父子分块。</li><li>[ ] 比较长度、重叠和结构保留。</li><li>[ ] 处理列表、表格和超长段落。</li><li>[ ] 支持版本、更新、删除和重新索引。</li></ul><h3 id="retrieval" tabindex="-1">Retrieval <a class="header-anchor" href="#retrieval" aria-label="Permalink to &quot;Retrieval&quot;">​</a></h3><ul><li>[ ] Dense、Keyword、Hybrid。</li><li>[ ] Metadata Filter、权限过滤。</li><li>[ ] Query Rewrite、Multi-query、实体与时间过滤。</li><li>[ ] Top-K、Threshold、Rerank。</li><li>[ ] 无相关结果时不强行回答。</li></ul><h3 id="evaluation" tabindex="-1">Evaluation <a class="header-anchor" href="#evaluation" aria-label="Permalink to &quot;Evaluation&quot;">​</a></h3><ul><li>[ ] 至少 50 条真实问题。</li><li>[ ] 每条定义相关文档和参考答案。</li><li>[ ] Recall@K、Context Relevance、Groundedness、Citation Accuracy。</li><li>[ ] 无答案、过期资料、冲突来源和权限测试。</li><li>[ ] 修改 Chunk、检索或模型后运行回归。</li></ul><p>验收：能定位问题发生在解析、检索、重排、上下文、生成还是引用阶段。</p><hr><h2 id="阶段六-tool-calling-与-mcp" tabindex="-1">阶段六：Tool Calling 与 MCP <a class="header-anchor" href="#阶段六-tool-calling-与-mcp" aria-label="Permalink to &quot;阶段六：Tool Calling 与 MCP&quot;">​</a></h2><h3 id="tool-设计" tabindex="-1">Tool 设计 <a class="header-anchor" href="#tool-设计" aria-label="Permalink to &quot;Tool 设计&quot;">​</a></h3><ul><li>[ ] 名称和描述清晰。</li><li>[ ] 单一职责、Schema 简洁、输出稳定。</li><li>[ ] 输入验证、超时、有限重试、幂等。</li><li>[ ] 只读与写入工具分开。</li><li>[ ] 写操作显示影响范围并请求确认。</li><li>[ ] 权限、审计、脱敏和错误隔离。</li></ul><h3 id="mcp" tabindex="-1">MCP <a class="header-anchor" href="#mcp" aria-label="Permalink to &quot;MCP&quot;">​</a></h3><ul><li>[ ] Host、Client、Server。</li><li>[ ] Transport、Tools、Resources、Prompts、Capabilities。</li><li>[ ] 使用 Inspector 调试。</li><li>[ ] 开发本地 Server。</li><li>[ ] 增加认证、授权和日志。</li><li>[ ] 防止任意文件、URL、命令访问和 SSRF。</li></ul><p>验收：模型不拥有最终权限；所有参数和权限由服务端重新校验。</p><hr><h2 id="阶段七-workflow-与-agent" tabindex="-1">阶段七：Workflow 与 Agent <a class="header-anchor" href="#阶段七-workflow-与-agent" aria-label="Permalink to &quot;阶段七：Workflow 与 Agent&quot;">​</a></h2><p>优先使用可预测 Workflow，固定流程可解决时不优先使用自由 Agent。</p><h3 id="workflow-模式" tabindex="-1">Workflow 模式 <a class="header-anchor" href="#workflow-模式" aria-label="Permalink to &quot;Workflow 模式&quot;">​</a></h3><ul><li>[ ] Prompt Chaining。</li><li>[ ] Routing。</li><li>[ ] Parallelization。</li><li>[ ] Orchestrator-Workers。</li><li>[ ] Evaluator-Optimizer。</li></ul><h3 id="agent-组件" tabindex="-1">Agent 组件 <a class="header-anchor" href="#agent-组件" aria-label="Permalink to &quot;Agent 组件&quot;">​</a></h3><ul><li>[ ] Goal、State、Planner、Tools、Executor、Evaluator、Memory、Stop Condition、Human Approval。</li><li>[ ] 最大步骤、Token、成本和总超时。</li><li>[ ] 暂停、取消、恢复、失败步骤和部分完成。</li><li>[ ] 防止循环、重复操作和重试风暴。</li></ul><h3 id="长任务架构" tabindex="-1">长任务架构 <a class="header-anchor" href="#长任务架构" aria-label="Permalink to &quot;长任务架构&quot;">​</a></h3><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>创建 Task → 数据库 → Queue → Worker → 持久化步骤 → 推送进度 → 完成</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>验收：任务可观测、可恢复、高风险动作需确认，能量化最终任务完成率。</p><hr><h2 id="阶段八-evaluation" tabindex="-1">阶段八：Evaluation <a class="header-anchor" href="#阶段八-evaluation" aria-label="Permalink to &quot;阶段八：Evaluation&quot;">​</a></h2><p>评估维度：Correctness、Relevance、Completeness、Format、Safety、Latency、Cost、Groundedness、Tool Selection、Task Completion。</p><ul><li>[ ] 从真实请求收集正常、边界、无答案、权限和对抗样例。</li><li>[ ] 为 Bug 增加回归样例。</li><li>[ ] 使用确定性检查、人工评估和 LLM Judge。</li><li>[ ] 测试 Judge 的稳定性。</li><li>[ ] 同时记录质量、延迟和成本。</li><li>[ ] 设置上线门槛和 CI 回归。</li><li>[ ] 线上失败回流到离线评估集。</li></ul><p>验收：每次改 Prompt、模型、检索、Tool 或 Agent，都能量化质量变化。</p><hr><h2 id="阶段九-生产工程" tabindex="-1">阶段九：生产工程 <a class="header-anchor" href="#阶段九-生产工程" aria-label="Permalink to &quot;阶段九：生产工程&quot;">​</a></h2><h3 id="model-gateway" tabindex="-1">Model Gateway <a class="header-anchor" href="#model-gateway" aria-label="Permalink to &quot;Model Gateway&quot;">​</a></h3><ul><li>[x] <a href="./notes/14-production-engineering/01-model-gateway-cache-queue-observability-reliability#2-模型网关统一能力而非抹平差异">Generate、Stream、Embed、Structured Output、Tool、Usage 和 Error 的统一接口</a>。</li><li>[x] <a href="./notes/14-production-engineering/01-model-gateway-cache-queue-observability-reliability#路由决策">多模型路由、Fallback、超时、重试</a>。</li><li>[x] <a href="./notes/14-production-engineering/01-model-gateway-cache-queue-observability-reliability#路由决策">按任务、复杂度、上下文、延迟、成本和合规选择模型</a>。</li></ul><h3 id="cache-与-queue" tabindex="-1">Cache 与 Queue <a class="header-anchor" href="#cache-与-queue" aria-label="Permalink to &quot;Cache 与 Queue&quot;">​</a></h3><ul><li>[x] <a href="./notes/14-production-engineering/01-model-gateway-cache-queue-observability-reliability#3-缓存复用结果但不跨越权限和新鲜度">Exact、Semantic、Retrieval、Tool Result 和 Prefix Cache</a>。</li><li>[x] <a href="./notes/14-production-engineering/01-model-gateway-cache-queue-observability-reliability#3-缓存复用结果但不跨越权限和新鲜度">租户隔离、过期、失效和命中率</a>。</li><li>[x] <a href="./notes/14-production-engineering/01-model-gateway-cache-queue-observability-reliability#4-queue把可等待工作从同步路径移走">文档解析、Embedding、批量生成和 Agent 长任务进入队列</a>。</li><li>[x] <a href="./notes/14-production-engineering/01-model-gateway-cache-queue-observability-reliability#队列合同与幂等">重试、死信、幂等、取消、进度和配额</a>。</li></ul><h3 id="observability" tabindex="-1">Observability <a class="header-anchor" href="#observability" aria-label="Permalink to &quot;Observability&quot;">​</a></h3><ul><li>[x] <a href="./notes/14-production-engineering/01-model-gateway-cache-queue-observability-reliability#5-可观测性从一次答案追到每个决定">Request ID、User、Tenant、Model、Prompt Version</a>。</li><li>[x] <a href="./notes/14-production-engineering/01-model-gateway-cache-queue-observability-reliability#5-可观测性从一次答案追到每个决定">Token、Cost、首 Token 延迟和总时长</a>。</li><li>[x] <a href="./notes/14-production-engineering/01-model-gateway-cache-queue-observability-reliability#5-可观测性从一次答案追到每个决定">Retrieval Query、过滤、结果与分数</a>。</li><li>[x] <a href="./notes/14-production-engineering/01-model-gateway-cache-queue-observability-reliability#5-可观测性从一次答案追到每个决定">Tool 参数、结果、审批和错误</a>。</li><li>[x] <a href="./notes/14-production-engineering/01-model-gateway-cache-queue-observability-reliability#5-可观测性从一次答案追到每个决定">Agent Step、状态、停止原因</a>。</li></ul><h3 id="reliability" tabindex="-1">Reliability <a class="header-anchor" href="#reliability" aria-label="Permalink to &quot;Reliability&quot;">​</a></h3><ul><li>[x] <a href="./notes/14-production-engineering/01-model-gateway-cache-queue-observability-reliability#6-可靠性机制的适用边界">Timeout、Backoff、Jitter、Circuit Breaker、Rate Limit、Fallback、Partial Success</a>。</li></ul><p>验收：线上问题能定位到具体模型、Prompt、上下文、检索、Tool 或 Agent 步骤。</p><hr><h2 id="阶段十-安全与治理" tabindex="-1">阶段十：安全与治理 <a class="header-anchor" href="#阶段十-安全与治理" aria-label="Permalink to &quot;阶段十：安全与治理&quot;">​</a></h2><ul><li>[x] <a href="./notes/15-security-governance/01-prompt-injection-permissions-audit-and-red-team#1-威胁模型谁能控制什么">Prompt Injection 和间接注入</a>。</li><li>[x] <a href="./notes/15-security-governance/01-prompt-injection-permissions-audit-and-red-team#2-把指令数据和能力拆开">外部网页、邮件、PDF、数据库和 Tool 结果视为不可信数据</a>。</li><li>[x] <a href="./notes/15-security-governance/01-prompt-injection-permissions-audit-and-red-team#3-最小权限与租户隔离">服务端最小权限和租户隔离</a>。</li><li>[x] <a href="./notes/15-security-governance/01-prompt-injection-permissions-audit-and-red-team#4-写操作确认不是一个按钮而是受约束的交易">写操作确认、二次验证、幂等和审计</a>。</li><li>[x] <a href="./notes/15-security-governance/01-prompt-injection-permissions-audit-and-red-team#5-日志保留和删除">日志脱敏、数据保存周期和删除机制</a>。</li><li>[x] <a href="./notes/15-security-governance/01-prompt-injection-permissions-audit-and-red-team#6-文件网络命令与沙箱">限制文件路径、网络目标、命令和执行沙箱</a>。</li><li>[x] <a href="./notes/15-security-governance/01-prompt-injection-permissions-audit-and-red-team#7-第三方-mcp-server-审查">对第三方 MCP Server 做安全审查</a>。</li><li>[x] <a href="./notes/15-security-governance/01-prompt-injection-permissions-audit-and-red-team#8-红队把攻击假设变成可重复测试">Red Team：泄露 Prompt、跨租户、删除数据、内网访问、重复支付、资源消耗</a>。</li></ul><p>验收：模型无法绕过服务端权限；所有高风险动作可审计且需要确认。</p><hr><h2 id="阶段十一-进阶选修" tabindex="-1">阶段十一：进阶选修 <a class="header-anchor" href="#阶段十一-进阶选修" aria-label="Permalink to &quot;阶段十一：进阶选修&quot;">​</a></h2><h3 id="开源模型与本地推理" tabindex="-1">开源模型与本地推理 <a class="header-anchor" href="#开源模型与本地推理" aria-label="Permalink to &quot;开源模型与本地推理&quot;">​</a></h3><p><a href="./notes/16-advanced-options/01-local-inference-and-fine-tuning-decisions#2-开源模型与本地推理的组成">Hugging Face、量化、显存、Batch、Throughput、Latency、KV Cache、Serving、许可证和总持有成本</a>。</p><h3 id="fine-tuning" tabindex="-1">Fine-tuning <a class="header-anchor" href="#fine-tuning" aria-label="Permalink to &quot;Fine-tuning&quot;">​</a></h3><p><a href="./notes/16-advanced-options/01-local-inference-and-fine-tuning-decisions#7-fine-tuning-的输入输出与风险">Fine-tuning 的适用条件、PEFT/LoRA、数据与评估、训练恢复和发布</a>：仅在 Prompt、上下文、RAG、Tool 和模型选择都不能解决，并拥有高质量数据和评估集时使用。</p><hr><h2 id="持续更新机制" tabindex="-1">持续更新机制 <a class="header-anchor" href="#持续更新机制" aria-label="Permalink to &quot;持续更新机制&quot;">​</a></h2><h3 id="每日-一个可复现的-ai-实验" tabindex="-1">每日：一个可复现的 AI 实验 <a class="header-anchor" href="#每日-一个可复现的-ai-实验" aria-label="Permalink to &quot;每日：一个可复现的 AI 实验&quot;">​</a></h3><ul><li>[ ] 从 Prompt、Context、Structured Output、RAG、Tool、Workflow、Agent、Evaluation 或 Safety 中选择一个小问题。</li><li>[ ] 固定任务与样例，只改变一个变量。</li><li>[ ] 记录模型完整标识、接口/框架版本、日期和配置。</li><li>[ ] 同时记录质量、延迟、Token、成本、失败类型和安全影响。</li><li>[ ] 保存输入、输出、Trace 或截图等证据，不只记录“效果不错”。</li><li>[ ] 得出可证伪结论，并说明适用范围和下一次实验。</li></ul><h3 id="每周-能力与案例更新" tabindex="-1">每周：能力与案例更新 <a class="header-anchor" href="#每周-能力与案例更新" aria-label="Permalink to &quot;每周：能力与案例更新&quot;">​</a></h3><ul><li>[ ] 精读一个官方文档、技术报告、模型卡、协议变更或高质量工程案例。</li><li>[ ] 用现有评估集复测一个新模型、新能力或框架升级。</li><li>[ ] 把线上失败或实验失败加入回归样例。</li><li>[ ] 更新一张能力卡：它解决什么、不能解决什么、成本和替代方案是什么。</li></ul><h3 id="每季度-路线图维护" tabindex="-1">每季度：路线图维护 <a class="header-anchor" href="#每季度-路线图维护" aria-label="Permalink to &quot;每季度：路线图维护&quot;">​</a></h3><ul><li>[ ] 检查官方 API、模型生命周期、SDK 和协议版本变化。</li><li>[ ] 检查 RAG、Agent、Evaluation、Safety 与多模态是否出现稳定的新实践。</li><li>[ ] 删除只绑定过时框架的内容，保留稳定原理和迁移说明。</li><li>[ ] 在仓库变更记录中写明新增、修改、废弃及证据来源。</li></ul><p>更新原则：官方文档、规范、论文和可复现实验优先于二手资讯；新能力必须经过固定评估集，而不是仅凭演示判断。</p><hr><h2 id="学习资源" tabindex="-1">学习资源 <a class="header-anchor" href="#学习资源" aria-label="Permalink to &quot;学习资源&quot;">​</a></h2><p>书籍：动手学深度学习、Hands-On Large Language Models、Build a Large Language Model From Scratch、AI Engineering、Designing Machine Learning Systems、Machine Learning Design Patterns、DDIA、Release It!。</p><p>网站与博客：<a href="https://huggingface.co/learn" target="_blank" rel="noreferrer">Hugging Face Learn</a>、<a href="https://modelcontextprotocol.io/" target="_blank" rel="noreferrer">Model Context Protocol</a>、<a href="https://www.anthropic.com/engineering" target="_blank" rel="noreferrer">Anthropic Engineering</a>、3Blue1Brown、Andrej Karpathy、fast.ai、Simon Willison、Lilian Weng、Chip Huyen、Eugene Yan、Hamel Husain、Latent Space。优先阅读所用模型和 SDK 的官方文档与模型卡。</p><hr>',103)])])}const m=a(r,[["render",n]]);export{p as __pageData,m as default};
